{
    // EF 9 breaking change #3: synchronous I/O (ToList, First, Single, …) now
    // throws InvalidOperationException on the Cosmos provider. Use async APIs.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — works unchanged because we kept "Discriminator" above.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

